const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    if (!member) return sendError(res, 409, 'MEMBER_DUPLICATE', 'Member already exists');
  res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'DUPLICATE_MEMBER') {
      return sendError(res, 409, 'DUPLICATE_MEMBER', 'Member already exists');
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const membersStore = [];

async function addMember(projectId, userId, role) {
  const existingMember = membersStore.find(m => m.projectId === projectId && m.userId === userId);
  if (existingMember) {
    return null;
  }
  const member = { id: randomUUID(), projectId, userId, role };
  membersStore.push(member);
  return member;
}

module.exports = {
  addMember,
};

